
"use client"

import { useState, useEffect } from "react";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Settings, Share2, Zap, MapPin, Loader2, Edit3, Check, UserCircle, Car, Gauge, Cpu } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useUser, useDoc, useFirestore, useMemoFirebase, updateDocumentNonBlocking } from "@/firebase";
import { doc } from "firebase/firestore";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";
import { CarIcons, RenderCarIcon, CarIconType } from "@/components/icons/car-icons";

const KOSOVO_CITIES = [
  "Prishtinë", "Prizren", "Pejë", "Gjakovë", "Mitrovicë", "Gjilan", "Ferizaj", 
  "Vushtrri", "Podujevë", "Rahovec", "Fushë Kosovë", "Suharekë", "Kaçanik", 
  "Skënderaj", "Lipjan", "Malishevë", "Drenas", "Deçan", "Klinë", "Kamenicë", 
  "Dragash", "Istog", "Viti", "Obiliq", "Leposaviq", "Graçanicë", "Hani i Elezit", 
  "Zveçan", "Shtime", "Novobërdë", "Zubin Potok", "Junik", "Mamushë", 
  "Ranillug", "Partesh", "Kllokot"
];

const ICON_LIST: { id: CarIconType; label: string }[] = [
  { id: 'turbo', label: 'Turbo' },
  { id: 'speedometer', label: 'Gauge' },
  { id: 'crown', label: 'King' },
  { id: 'lightning', label: 'Bolt' },
  { id: 'shield', label: 'Pro' },
  { id: 'flame', label: 'Fire' },
];

export default function ProfilePage() {
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const { toast } = useToast();
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);

  const [formData, setFormData] = useState({
    username: "",
    city: "",
    carBrand: "",
    carModel: "",
    horsepower: 0,
    modifications: "",
    profileIcon: "speedometer" as CarIconType,
  });

  const profileRef = useMemoFirebase(() => {
    if (!user || !db) return null;
    return doc(db, "users", user.uid);
  }, [user, db]);

  const { data: profile, isLoading: isProfileLoading } = useDoc(profileRef);

  useEffect(() => {
    if (profile) {
      setFormData({
        username: profile.username || "",
        city: profile.city || "Prishtinë",
        carBrand: profile.carBrand || "",
        carModel: profile.carModel || "",
        horsepower: profile.horsepower || 0,
        modifications: profile.modifications || "",
        profileIcon: (profile.profileIcon as CarIconType) || "speedometer",
      });
    }
  }, [profile]);

  const handleSaveProfile = () => {
    if (!profileRef) return;

    const updatedData = {
      ...formData,
      horsepower: Number(formData.horsepower),
      updatedAt: new Date().toISOString(),
    };

    updateDocumentNonBlocking(profileRef, updatedData);
    
    toast({
      title: "Profili u përditësua",
      description: "Distinktivi dhe të dhënat u ruajtën me sukses.",
    });
    
    setIsEditDialogOpen(false);
  };

  if (isUserLoading || isProfileLoading) {
    return (
      <div className="flex flex-col min-h-screen bg-background items-center justify-center">
        <Loader2 className="w-10 h-10 text-accent animate-spin" />
      </div>
    );
  }

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 overflow-x-hidden no-scrollbar">
      <div className="p-6 flex justify-between items-center z-20">
        <div className="flex items-center gap-2">
          <UserCircle className="w-6 h-6 text-accent" />
          <h1 className="text-xl font-black italic uppercase tracking-tighter">PROFILI IM</h1>
        </div>
        <div className="flex gap-2">
          <Button size="icon" variant="outline" className="rounded-xl glass border-white/10 w-10 h-10"><Share2 className="w-4 h-4" /></Button>
          <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
            <DialogTrigger asChild>
              <Button size="icon" variant="outline" className="rounded-xl glass border-white/10 w-10 h-10">
                <Settings className="w-4 h-4" />
              </Button>
            </DialogTrigger>
            <DialogContent className="glass border-white/10 text-foreground sm:max-w-[425px] max-h-[90vh] overflow-y-auto no-scrollbar rounded-[2.5rem]">
              <DialogHeader>
                <DialogTitle className="text-xl font-black italic uppercase tracking-tighter">Ndrysho Profilin</DialogTitle>
              </DialogHeader>
              <div className="grid gap-6 py-4">
                <div className="grid gap-2">
                  <Label htmlFor="username" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Emri i Përdoruesit</Label>
                  <Input 
                    id="username" 
                    value={formData.username} 
                    onChange={(e) => setFormData({...formData, username: e.target.value})}
                    className="bg-white/5 border-white/10 rounded-xl"
                  />
                </div>
                
                <div className="grid gap-3">
                  <Label className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Zgjidh Distinktivin (Automotive Badge)</Label>
                  <div className="grid grid-cols-3 gap-3">
                    {ICON_LIST.map((item) => (
                      <button
                        key={item.id}
                        onClick={() => setFormData({...formData, profileIcon: item.id})}
                        className={cn(
                          "relative aspect-square rounded-2xl flex flex-col items-center justify-center border-2 transition-all p-2",
                          formData.profileIcon === item.id 
                            ? "border-accent bg-accent/10 shadow-[0_0_15px_rgba(77,224,244,0.3)]" 
                            : "border-white/5 bg-white/[0.02] opacity-60 hover:opacity-100"
                        )}
                      >
                        <RenderCarIcon type={item.id} className={cn("w-8 h-8", formData.profileIcon === item.id ? "text-accent" : "text-white/60")} />
                        <span className="text-[8px] font-black uppercase mt-2 tracking-widest">{item.label}</span>
                        {formData.profileIcon === item.id && (
                          <div className="absolute top-1 right-1">
                            <Check className="text-accent w-3 h-3" />
                          </div>
                        )}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="grid gap-2">
                  <Label htmlFor="city" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Qyteti i Kosovës</Label>
                  <Select 
                    value={formData.city} 
                    onValueChange={(value) => setFormData({...formData, city: value})}
                  >
                    <SelectTrigger className="bg-white/5 border-white/10 rounded-xl h-12">
                      <SelectValue placeholder="Zgjidh qytetin" />
                    </SelectTrigger>
                    <SelectContent className="glass border-white/10 max-h-[300px]">
                      {KOSOVO_CITIES.map((city) => (
                        <SelectItem key={city} value={city} className="font-bold text-xs uppercase italic">
                          {city}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                
                <div className="grid gap-4">
                  <div className="grid gap-2">
                    <Label htmlFor="carBrand" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Marka e Mjetit</Label>
                    <Input 
                      id="carBrand"
                      placeholder="BMW, Audi..."
                      value={formData.carBrand} 
                      onChange={(e) => setFormData({...formData, carBrand: e.target.value})}
                      className="bg-white/5 border-white/10 rounded-xl"
                    />
                  </div>
                  <div className="grid gap-2">
                    <Label htmlFor="carModel" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Modeli i Mjetit</Label>
                    <Input 
                      id="carModel"
                      placeholder="M4, RS6..."
                      value={formData.carModel} 
                      onChange={(e) => setFormData({...formData, carModel: e.target.value})}
                      className="bg-white/5 border-white/10 rounded-xl"
                    />
                  </div>
                </div>

                <div className="grid gap-2">
                  <Label htmlFor="horsepower" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Fuqia (HP)</Label>
                  <Input 
                    id="horsepower" 
                    type="number"
                    value={formData.horsepower} 
                    onChange={(e) => setFormData({...formData, horsepower: parseInt(e.target.value) || 0})}
                    className="bg-white/5 border-white/10 rounded-xl"
                  />
                </div>
                <div className="grid gap-2">
                  <Label htmlFor="modifications" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Modifikimet</Label>
                  <Textarea 
                    id="modifications" 
                    placeholder="Stage 1, Downpipe..."
                    value={formData.modifications} 
                    onChange={(e) => setFormData({...formData, modifications: e.target.value})}
                    className="bg-white/5 border-white/10 rounded-xl min-h-[80px]"
                  />
                </div>
              </div>
              <DialogFooter className="pt-4">
                <Button onClick={handleSaveProfile} className="w-full bg-accent text-background font-black italic uppercase rounded-2xl h-14 shadow-xl neon-glow">
                  RUAJ NDRYSHIMET
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      <div className="px-6 py-4 relative z-10 flex flex-col items-center text-center">
        <div className="relative w-40 h-40 mb-6">
          <div className="absolute inset-0 rounded-[2.5rem] bg-gradient-to-br from-accent to-blue-600 animate-pulse opacity-20 blur-xl" />
          <div className="relative w-full h-full rounded-[2.5rem] bg-zinc-950 border-4 border-white/5 shadow-2xl flex items-center justify-center overflow-hidden">
            <RenderCarIcon type={profile?.profileIcon} className="w-20 h-20 text-accent drop-shadow-[0_0_10px_rgba(77,224,244,0.5)]" />
          </div>
          <div className="absolute -bottom-2 -right-2 bg-accent text-background rounded-full p-2 border-4 border-background shadow-lg">
            <Check className="w-4 h-4" />
          </div>
        </div>

        <div className="space-y-2">
          <h1 className="text-3xl font-black italic tracking-tighter uppercase leading-none">
            {profile?.username || 'Shofer i Ri'}
          </h1>
          <div className="flex items-center justify-center gap-2">
            <Badge variant="outline" className="bg-accent/10 border-accent/20 text-accent font-black px-4 py-1 rounded-full text-[10px]">
              {profile?.isPremium ? 'PREMIUM' : 'SHOFER KOSOVAR'}
            </Badge>
            <div className="flex items-center gap-1.5 text-[10px] font-black text-muted-foreground uppercase bg-white/5 px-4 py-1 rounded-full border border-white/5">
              <MapPin className="w-3.5 h-3.5 text-accent" />
              {profile?.city || 'Kosovë'}
            </div>
          </div>
        </div>

        <div className="flex gap-3 w-full mt-8">
          {[
            { label: "Ndjekës", val: "0" },
            { label: "Gara", val: "0" },
            { label: "Rangu", val: "--", accent: true }
          ].map((stat, i) => (
            <div key={i} className="flex-1 glass rounded-[1.8rem] p-4 border-white/5 flex flex-col items-center">
              <p className="text-[9px] font-black text-muted-foreground uppercase tracking-widest mb-1">{stat.label}</p>
              <p className={cn("text-xl font-black italic", stat.accent && "text-accent")}>{stat.val}</p>
            </div>
          ))}
        </div>
      </div>

      <div className="px-6 mt-6 space-y-4">
        <div className="flex items-center justify-between px-1">
          <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground">DETAJET E MJETIT</h2>
          <Button variant="ghost" size="sm" onClick={() => setIsEditDialogOpen(true)} className="text-accent hover:bg-accent/10 h-7 flex items-center gap-1 font-black italic text-[10px] uppercase">
            <Edit3 className="w-3.5 h-3.5" />
            Ndrysho
          </Button>
        </div>

        <Card className="glass border-accent/20 p-7 rounded-[2.5rem] space-y-6 relative overflow-hidden group shadow-2xl">
          {/* New Advanced Car Silhouette Visualization (F1 Blueprint Style) */}
          <div className="absolute -right-8 -bottom-10 w-80 h-48 opacity-20 group-hover:opacity-30 transition-all duration-700 pointer-events-none transform -rotate-12 translate-y-4">
            <svg viewBox="0 0 200 80" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-full h-full text-accent">
              <path d="M10 60C10 60 20 58 35 52C50 46 80 40 110 40C140 40 170 48 190 60H10Z" fill="url(#carGradient)" />
              <path d="M15 60L35 52C50 46 80 40 110 40C140 40 170 48 185 60" stroke="currentColor" strokeWidth="1" />
              <path d="M40 40C40 40 60 25 100 25C140 25 160 40 160 40" stroke="currentColor" strokeWidth="1" strokeDasharray="4 4" />
              <circle cx="45" cy="62" r="10" stroke="currentColor" strokeWidth="1" />
              <circle cx="155" cy="62" r="10" stroke="currentColor" strokeWidth="1" />
              <circle cx="45" cy="62" r="4" fill="currentColor" />
              <circle cx="155" cy="62" r="4" fill="currentColor" />
              <defs>
                <linearGradient id="carGradient" x1="100" y1="40" x2="100" y2="60" gradientUnits="userSpaceOnUse">
                  <stop stopColor="currentColor" stopOpacity="0.2" />
                  <stop offset="1" stopColor="currentColor" stopOpacity="0" />
                </linearGradient>
              </defs>
            </svg>
          </div>

          <div className="relative z-10 flex flex-col gap-1">
            <div className="flex items-center gap-3">
              <div className="w-1.5 h-10 bg-accent rounded-full neon-glow" />
              <div>
                <h3 className="text-3xl font-black italic text-white uppercase tracking-tighter leading-none mb-1">
                  {profile?.carBrand || 'Pa specifikuar'}
                </h3>
                <p className="text-lg font-black italic text-accent/80 uppercase tracking-tighter leading-none">
                  {profile?.carModel || ''}
                </p>
              </div>
            </div>
            <div className="mt-4 flex items-center gap-2">
              <Badge className="bg-white/5 border-white/10 text-accent font-black text-[9px] px-3 py-1 rounded-lg">
                <Cpu className="w-3 h-3 mr-1.5" />
                {profile?.horsepower || 0} HP
              </Badge>
              <Badge className="bg-white/5 border-white/10 text-muted-foreground font-black text-[9px] px-3 py-1 rounded-lg uppercase">
                KONFIGURIMI AKTUAL
              </Badge>
            </div>
          </div>
          
          <div className="relative z-10 grid grid-cols-3 gap-4 pt-8 border-t border-white/10">
            {[
              { label: "0-100", val: "--", unit: "sek", icon: Zap },
              { label: "100-200", val: "--", unit: "sek", icon: Gauge },
              { label: "TOP SPEED", val: "--", unit: "km/h", icon: Car }
            ].map((stat, i) => (
              <div key={i} className="text-center group/stat">
                <p className="text-[9px] font-black text-muted-foreground uppercase tracking-widest mb-3 group-hover/stat:text-accent transition-colors flex items-center justify-center gap-1.5">
                  <stat.icon className="w-2.5 h-2.5" />
                  {stat.label}
                </p>
                <div className="flex flex-col items-center">
                  <span className="text-2xl font-black italic text-white leading-none tracking-tighter tabular-nums mb-1">{stat.val}</span>
                  <span className="text-[8px] font-black text-accent uppercase tracking-widest">{stat.unit}</span>
                </div>
              </div>
            ))}
          </div>

          {/* Top accent line */}
          <div className="absolute top-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-accent/40 to-transparent" />
        </Card>

        <div className="glass rounded-[2rem] p-6 border-white/5 space-y-4 shadow-xl">
          <h4 className="text-[10px] font-black text-accent uppercase tracking-widest flex items-center gap-2 mb-2">
            <Zap className="w-3.5 h-3.5" />
            MODIFIKIMET E LISTUARA
          </h4>
          <div className="flex flex-wrap gap-2">
            {profile?.modifications ? (
              profile.modifications.split(',').map((mod: string, i: number) => (
                <Badge key={i} variant="outline" className="bg-white/5 border-white/10 text-[10px] font-black italic py-2 px-4 rounded-xl uppercase tracking-tighter">
                  {mod.trim()}
                </Badge>
              ))
            ) : (
              <p className="text-[11px] font-bold text-muted-foreground italic uppercase tracking-widest px-1">Nuk ka modifikime të listuara</p>
            )}
          </div>
        </div>
      </div>

      <BottomNav />
    </div>
  );
}
